function SearchFilter({
  search,
  setSearch,
  date,
  setDate
}) {
  return (
    <div className="search-filter">

      <input
        type="text"
        placeholder="Search by name, email or message..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      <input
        type="date"
        value={date}
        onChange={(e) => setDate(e.target.value)}
      />

    </div>
  );
}

export default SearchFilter;
